import { readFile, writeFile } from "node:fs/promises";
import { createForks, createWorkspace } from "@tigrisdata/agent-kit";
import { get, put } from "@tigrisdata/storage";

const normalizeBucketName = (name: string) =>
  name.toLowerCase().replace(/[^a-z0-9.-]/g, "-");

const formatError = (error: unknown): string => {
  if (!error) {
    return "Unknown error";
  }

  if (typeof error === "string") {
    return error;
  }

  if (error instanceof Error) {
    const details: string[] = [];
    const anyError = error as Error & { code?: string; $metadata?: { httpStatusCode?: number }; cause?: unknown };
    if (anyError.code) {
      details.push(`code=${anyError.code}`);
    }
    if (anyError.$metadata?.httpStatusCode) {
      details.push(`httpStatus=${anyError.$metadata.httpStatusCode}`);
    }
    if (anyError.cause) {
      details.push(`cause=${formatError(anyError.cause)}`);
    }
    const detailSuffix = details.length ? ` (${details.join(", ")})` : "";
    return `${error.name}: ${error.message}${detailSuffix}`;
  }

  try {
    return JSON.stringify(error);
  } catch {
    return String(error);
  }
};

const assertError = (message: string, error: unknown) => {
  const description = formatError(error);
  console.error(message, description);
  process.exit(1);
};

const main = async () => {
  const trialIdRaw = await readFile("/logs/artifacts/trial_id", "utf-8");
  const trialId = trialIdRaw.trim().toLowerCase();
  if (!trialId) {
    console.error("trial_id is empty");
    process.exit(1);
  }

  const workspaceName = normalizeBucketName(`harbor-ro-${trialId}`);

  const workspaceResult = await createWorkspace(workspaceName, {
    ttl: { days: 1 },
    enableSnapshots: true,
    credentials: { role: "Editor" },
  });

  if (workspaceResult.error || !workspaceResult.data?.credentials) {
    assertError("Failed to create workspace", workspaceResult.error);
  }

  const editorCreds = workspaceResult.data.credentials;

  const putResult = await put("notes/welcome.txt", "hello readonly", {
    config: {
      bucket: workspaceName,
      accessKeyId: editorCreds.accessKeyId,
      secretAccessKey: editorCreds.secretAccessKey,
    },
  });

  if (putResult.error) {
    assertError("Failed to upload welcome.txt", putResult.error);
  }

  const forkPrefix = normalizeBucketName(`harbor-ro-${trialId}-readonly`);
  const forkResult = await createForks(workspaceName, 1, {
    prefix: forkPrefix,
    credentials: { role: "ReadOnly" },
  });

  const forkInfo = forkResult.data?.forkSet?.forks?.[0];
  if (forkResult.error || !forkInfo?.credentials) {
    assertError("Failed to create readonly fork", forkResult.error);
  }

  const forkBucket = normalizeBucketName(forkInfo.bucket ?? `${forkPrefix}-0`);
  const readonlyCreds = forkInfo.credentials;

  const forbiddenWrite = await put("notes/forbidden.txt", "should be rejected", {
    config: {
      bucket: forkBucket,
      accessKeyId: readonlyCreds.accessKeyId,
      secretAccessKey: readonlyCreds.secretAccessKey,
    },
  });

  if (!forbiddenWrite.error) {
    console.error("Readonly write unexpectedly succeeded");
    process.exit(1);
  }

  const denialMessage = formatError(forbiddenWrite.error);
  if (!denialMessage.trim()) {
    console.error("Readonly write denied, but error message is empty");
    process.exit(1);
  }

  await writeFile("/home/user/tigris-task/write-denial.log", denialMessage, "utf-8");

  const readResult = await get("notes/welcome.txt", "string", {
    config: {
      bucket: forkBucket,
      accessKeyId: readonlyCreds.accessKeyId,
      secretAccessKey: readonlyCreds.secretAccessKey,
    },
  });

  if (readResult.error || readResult.data !== "hello readonly") {
    assertError("Failed to read welcome.txt from readonly fork", readResult.error);
  }

  await writeFile("/home/user/tigris-task/readback.txt", readResult.data, "utf-8");
};

main().catch((error) => {
  console.error("Unhandled error", formatError(error));
  process.exit(1);
});

